                if (s.uuid && COHORT_DB && COHORT_DB.students && COHORT_DB.students[s.uuid]) {
                    COHORT_DB.students[s.uuid].status = n.status || 'active';
                }
                this.renderCurrentTab();
                UI.toast("瀹歌弓鎱ㄩ弨?(鐠囬鍋ｉ崙璁崇箽鐎?", "success");
