        // 4. 閸氬本顒為弴瀛樻煀娑撹崵鏅棃銏㈡畱鏉堟挸鍙嗗?(绾喕绻?processData 鏉╂劘顢戦弮鎯板厴鐠囪鍩?
        const main1 = document.getElementById('ind1');
        const main2 = document.getElementById('ind2');
