// 閹嗗厴娴兼ê瀵插銉ュ徔
const Perf = {
    // 瀵倹顒炴禒璇插閸栧懓顥婇崳顭掔窗鐟欙絽鍠呴悙鐟板毊閹稿鎸抽崥搴ｆ櫕闂堚懇鈧粌浜ｅ鐑┾偓婵堟畱闂傤噣顣?
    runAsync: (fn, loadingText) => {
        UI.loading(true, loadingText);
        // 閸掆晝鏁?setTimeout 鐏忓棔鎹㈤崝鈩冨腹閸掗绗呮稉鈧敮褝绱濈拋?UI 閸忓牊瑕嗛弻鎾冲毉 Loading
        setTimeout(async () => {
            try {
                await fn();
            } catch (e) {
                console.error(e);
                UI.toast("閸欐垹鏁撻柨娆掝嚖: " + e.message, 'error');
            } finally {
                UI.loading(false);
            }
        }, 50);
    },
    // 妤傛ɑ鈧嗗厴閸掓銆冨〒鍙夌厠閿涙俺袙閸?+= HTML 鐎佃壈鍤ч惃鍕幢妞?
    renderList: (data, templateFn) => {
        if (!data || !data.length) return '';
        return data.map(templateFn).join('');
    }
};
