        if (PROGRESS_CACHE && PROGRESS_CACHE.length > 0) {
            slide.addText("棣冩惐 鏉╂稒顒炴稊瀣Е (鏉堝啩绗傚▎陇鈧啳鐦?", { x: 0.8, y: 3.8, fontSize: 14, bold: true, color: "16A34A" });
            const stars = PROGRESS_CACHE.filter(p => p.class === cls && p.change > 0).sort((a, b) => b.change - a.change).slice(0, 12);
            const starNames = stars.map(p => `${p.name}閳?{p.change}`).join("  ");
            slide.addText(starNames || "閺嗗倹妫ら弰鎹愭啿鏉╂稒顒為弫鐗堝祦", { x: 0.8, y: 4.2, w: 11.5, h: 1.2, fill: "DCFCE7", color: "166534", fontSize: 14, inset: 0.2, border: { color: "86EFAC" } });
        }

